#!/bin/bash

# Check if the required parameter is provided
if [ -z "$1" ]; then
  echo "Error: Log filename not provided"
  exit 1
fi

LOGFILE=$1

# Create archive directory if it doesn't exist
mkdir -p /archive

# Copy log file to archive directory
cp /var/log/$LOGFILE /archive/$LOGFILE

echo "Log file $LOGFILE archived successfully"